    "id": "default_proto_1_2",
    "name": "Y-BALANCE TEST (YBT)",
    "category": "Screening",
    "blocks": [
      {
        "id": "blk_0",
        "type": "text_block",
        "lines": [
          {
            "id": "l0",
            "type": "paragraph",
            "content": "**Purpose:** Assess dynamic balance and asymmetry  "
          },
          {
            "id": "l1",
            "type": "paragraph",
            "content": "**Equipment:** Y-Balance Kit or tape measure  "
          },
          {
            "id": "l2",
            "type": "paragraph",
            "content": "**Time:** 10-15 minutes  "
          },
          {
            "id": "l3",
            "type": "paragraph",
            "content": "**Population:** All athletes, especially those with ankle/knee/hip injury risk"
          },
          {
            "id": "l4",
            "type": "heading2",
            "content": "Setup"
          },
          {
            "id": "l5",
            "type": "bullet",
            "content": "Three lines marked at 120° angles: Anterior, Posteromedial, Posterolateral"
          },
          {
            "id": "l6",
            "type": "bullet",
            "content": "Athlete stands barefoot on test leg at center"
          },
          {
            "id": "l7",
            "type": "bullet",
            "content": "Hands on hips"
          },
          {
            "id": "l8",
            "type": "heading2",
            "content": "Procedure"
          },
          {
            "id": "l9",
            "type": "numbered",
            "content": "**Familiarization:** 6 practice trials per direction per leg"
          },
          {
            "id": "l10",
            "type": "numbered",
            "content": "**Testing:** 3 trials per direction per leg"
          },
          {
            "id": "l11",
            "type": "numbered",
            "content": "Push reach indicator as far as possible with opposite leg"
          },
          {
            "id": "l12",
            "type": "numbered",
            "content": "Maintain single-leg stance throughout"
          },
          {
            "id": "l13",
            "type": "numbered",
            "content": "Return to bilateral stance with control"
          },
          {
            "id": "l14",
            "type": "numbered",
            "content": "Rest 15 seconds between trials"
          },
          {
            "id": "l15",
            "type": "heading2",
            "content": "Invalid Trial (repeat)"
          },
          {
            "id": "l16",
            "type": "bullet",
            "content": "Hands leave hips"
          },
          {
            "id": "l17",
            "type": "bullet",
            "content": "Stance foot lifts or shifts"
          },
          {
            "id": "l18",
            "type": "bullet",
            "content": "Fail to return to start"
          },
          {
            "id": "l19",
            "type": "bullet",
            "content": "Touch down with reach foot for support"
          },
          {
            "id": "l20",
            "type": "heading2",
            "content": "Measurements"
          },
          {
            "id": "l21",
            "type": "bullet",
            "content": "Record maximum reach distance (cm) for each direction"
          },
          {
            "id": "l22",
            "type": "bullet",
            "content": "Take best of 3 trials per direction"
          },
          {
            "id": "l23",
            "type": "bullet",
            "content": "Measure both legs"
          },
          {
            "id": "l24",
            "type": "heading2",
            "content": "Calculations"
          },
          {
            "id": "l25",
            "type": "bullet",
            "content": "**Anterior Reach (%)** = (Anterior Distance / Leg Length) × 100"
          },
          {
            "id": "l26",
            "type": "bullet",
            "content": "**Posteromedial Reach (%)** = (PM Distance / Leg Length) × 100"
          },
          {
            "id": "l27",
            "type": "bullet",
            "content": "**Posterolateral Reach (%)** = (PL Distance / Leg Length) × 100"
          },
          {
            "id": "l28",
            "type": "bullet",
            "content": "**Composite Score** = (ANT + PM + PL) / (Leg Length × 3) × 100"
          },
          {
            "id": "l29",
            "type": "paragraph",
            "content": "**Leg Length:** ASIS to medial malleolus"
          },
          {
            "id": "l30",
            "type": "heading2",
            "content": "Normative Data"
          },
          {
            "id": "l31",
            "type": "bullet",
            "content": "Composite Score >94% = Good"
          },
          {
            "id": "l32",
            "type": "bullet",
            "content": "Composite Score <89% = Increased injury risk"
          },
          {
            "id": "l33",
            "type": "bullet",
            "content": "Anterior reach asymmetry >4cm = 2.5x injury risk"
          },
          {
            "id": "l34",
            "type": "heading2",
            "content": "Interpretation"
          },
          {
            "id": "l35",
            "type": "bullet",
            "content": "Asymmetry >4cm: Increased risk (2.5x)"
          },
          {
            "id": "l36",
            "type": "bullet",
            "content": "Low composite scores: Decreased neuromuscular control"
          },
          {
            "id": "l37",
            "type": "bullet",
            "content": "Anterior direction most predictive of lower extremity injury"
          }
        ]
      }
    ],
